-- Seed 300 kosakata Kaigo (senmon yougo) ke tabel vocab (level_id=6, field='kaigo').
-- Sumber: 6 batch tematik (teknik kaijo, medis, tubuh/gejala, penyakit/demensia, alat bantu, sistem/peran).
-- ON CONFLICT (level_id, word) DO NOTHING agar idempoten; order_index dirapikan 1..N di akhir.







-- 8 kosakata tambahan untuk menggenapkan 300 (mengganti 8 kata yang bentrok antar-batch).
ON CONFLICT (level_id, word) DO NOTHING;

-- Rapikan order_index menjadi 1..N kontigu (menghapus celah akibat ON CONFLICT).
WITH ordered AS (
  SELECT id, row_number() OVER (ORDER BY order_index, created_at) AS rn
  FROM public.vocab
  WHERE level_id = 6 AND field = 'kaigo'
)
UPDATE public.vocab v
SET order_index = o.rn
FROM ordered o
WHERE v.id = o.id AND v.order_index <> o.rn;
