INSERT INTO public.vocab (level_id, word, hiragana, romaji, meaning, part_of_speech, usage_id, usage_jp, full_meaning, example_sentence, example_hiragana, example_meaning, order_index, field) VALUES
(6, '移乗介助', 'いじょうかいじょ', 'ijō kaijo', 'bantuan berpindah (transfer)', 'Kata benda', 'Membantu lansia berpindah dari tempat tidur ke kursi roda dan sebaliknya.', 'ベッドと車椅子の間などの移動を助けること', 'bantuan saat klien berpindah posisi antar tempat seperti dari ranjang ke kursi roda', '移乗介助のときは腰を痛めないように気をつけます。', 'いじょうかいじょのときはこしをいためないようにきをつけます。', 'Saat membantu berpindah, kami berhati-hati agar tidak melukai pinggang.', 1, 'kaigo'),
(6, '体位変換', 'たいいへんかん', 'taii henkan', 'mengubah posisi tubuh', 'Kata benda', 'Mengubah posisi tubuh lansia yang berbaring untuk mencegah luka tekan.', '寝ている人の姿勢を変えること', 'tindakan mengubah posisi tubuh klien yang berbaring untuk mencegah luka dekubitus', '二時間ごとに体位変換を行います。', 'にじかんごとにたいいへんかんをおこないます。', 'Kami melakukan perubahan posisi tubuh setiap dua jam.', 2, 'kaigo'),
(6, '清拭', 'せいしき', 'seishiki', 'menyeka tubuh', 'Kata benda', 'Membersihkan tubuh lansia dengan kain hangat ketika tidak bisa mandi.', '蒸しタオルなどで体を拭いて清潔にすること', 'membersihkan tubuh klien dengan handuk hangat saat mandi tidak memungkinkan', '入浴できない日は清拭で体を清潔にします。', 'にゅうよくできないひはせいしきでからだをせいけつにします。', 'Pada hari tidak bisa mandi, kami membersihkan tubuh dengan menyeka.', 3, 'kaigo'),
(6, '食事介助', 'しょくじかいじょ', 'shokuji kaijo', 'bantuan makan', 'Kata benda', 'Membantu lansia yang sulit makan sendiri saat waktu makan.', '自分で食べられない人の食事を助けること', 'bantuan saat memberi makan klien yang kesulitan makan sendiri', '食事介助では誤嚥に注意します。', 'しょくじかいじょではごえんにちゅういします。', 'Saat membantu makan, kami waspada terhadap tersedak.', 4, 'kaigo'),
(6, '排泄介助', 'はいせつかいじょ', 'haisetsu kaijo', 'bantuan buang air', 'Kata benda', 'Membantu lansia saat buang air kecil atau besar.', '排尿や排便を助けること', 'bantuan kepada klien saat buang air kecil maupun besar', '排泄介助はプライバシーに配慮します。', 'はいせつかいじょはプライバシーにはいりょします。', 'Saat membantu buang air, kami menjaga privasi klien.', 5, 'kaigo'),
(6, '入浴介助', 'にゅうよくかいじょ', 'nyūyoku kaijo', 'bantuan mandi', 'Kata benda', 'Membantu lansia masuk dan keluar bak mandi serta membersihkan tubuh.', '入浴の動作を助けること', 'bantuan saat klien mandi termasuk masuk dan keluar bak serta mencuci tubuh', '入浴介助では転倒に気をつけます。', 'にゅうよくかいじょではてんとうにきをつけます。', 'Saat membantu mandi, kami berhati-hati terhadap risiko jatuh.', 6, 'kaigo'),
(6, '口腔ケア', 'こうくうケア', 'kōkū kea', 'perawatan mulut', 'Kata benda', 'Membersihkan rongga mulut dan gigi lansia untuk mencegah infeksi.', '口の中を清潔に保つ手入れ', 'perawatan kebersihan rongga mulut dan gigi klien untuk mencegah infeksi', '毎食後に口腔ケアをします。', 'まいしょくごにこうくうケアをします。', 'Kami melakukan perawatan mulut setelah setiap makan.', 7, 'kaigo'),
(6, '整容', 'せいよう', 'seiyō', 'merapikan penampilan', 'Kata benda', 'Merapikan penampilan lansia seperti rambut dan wajah.', '身だしなみを整えること', 'membantu klien merapikan penampilan diri seperti rambut dan wajah', '朝の整容で気持ちが明るくなります。', 'あさのせいようできもちがあかるくなります。', 'Merapikan penampilan di pagi hari membuat hati menjadi cerah.', 8, 'kaigo'),
(6, '更衣介助', 'こういかいじょ', 'kōi kaijo', 'bantuan ganti baju', 'Kata benda', 'Membantu lansia mengganti pakaian.', '衣服の着脱を助けること', 'bantuan kepada klien saat memakai dan melepas pakaian', '更衣介助では麻痺側から袖を通します。', 'こういかいじょではまひがわからそでをとおします。', 'Saat membantu ganti baju, lengan baju dipasang dari sisi yang lumpuh dulu.', 9, 'kaigo'),
(6, '移動介助', 'いどうかいじょ', 'idō kaijo', 'bantuan bergerak', 'Kata benda', 'Membantu lansia berpindah tempat di dalam ruangan atau gedung.', '場所から場所への移動を助けること', 'bantuan saat klien berpindah dari satu tempat ke tempat lain', '車椅子での移動介助に慣れてきました。', 'くるまいすでのいどうかいじょになれてきました。', 'Saya sudah terbiasa membantu pergerakan dengan kursi roda.', 10, 'kaigo'),
(6, '歩行介助', 'ほこうかいじょ', 'hokō kaijo', 'bantuan berjalan', 'Kata benda', 'Membantu lansia berjalan agar tidak terjatuh.', '歩くことを支えて助けること', 'bantuan menopang klien saat berjalan agar tidak jatuh', '歩行介助では利用者の横に立ちます。', 'ほこうかいじょではりようしゃのよこにたちます。', 'Saat membantu berjalan, kami berdiri di samping klien.', 11, 'kaigo'),
(6, '起き上がり介助', 'おきあがりかいじょ', 'okiagari kaijo', 'bantuan bangkit duduk', 'Kata benda', 'Membantu lansia bangkit dari posisi berbaring ke posisi duduk.', '寝た状態から体を起こすのを助けること', 'bantuan saat klien bangkit dari berbaring menjadi posisi duduk', '起き上がり介助はゆっくり行います。', 'おきあがりかいじょはゆっくりおこないます。', 'Bantuan bangkit duduk dilakukan dengan perlahan.', 12, 'kaigo'),
(6, '寝返り', 'ねがえり', 'negaeri', 'membalikkan badan', 'Kata benda', 'Membantu lansia membalikkan badan saat berbaring di tempat tidur.', '寝たまま体の向きを変えること', 'gerakan membalikkan badan klien saat berbaring untuk mencegah luka tekan', '自分で寝返りができない方を支えます。', 'じぶんでねがえりができないかたをささえます。', 'Kami menopang klien yang tidak bisa membalikkan badan sendiri.', 13, 'kaigo'),
(6, '端座位', 'たんざい', 'tanzai', 'posisi duduk di tepi ranjang', 'Kata benda', 'Posisi lansia duduk di tepi tempat tidur dengan kaki menggantung.', 'ベッドの端に腰かけた姿勢', 'posisi duduk klien di tepi tempat tidur dengan kedua kaki menggantung', '端座位を保てるか確認します。', 'たんざいをたもてるかかくにんします。', 'Kami memeriksa apakah klien bisa mempertahankan posisi duduk di tepi ranjang.', 14, 'kaigo'),
(6, '立位保持', 'りついほじ', 'ritsui hoji', 'mempertahankan posisi berdiri', 'Kata benda', 'Kemampuan lansia berdiri dan menjaga posisi tetap berdiri.', '立った姿勢を保つこと', 'kemampuan klien berdiri dan mempertahankan posisi berdiri dengan stabil', '立位保持ができれば移乗が楽になります。', 'りついほじができればいじょうがらくになります。', 'Jika bisa mempertahankan berdiri, proses berpindah menjadi lebih mudah.', 15, 'kaigo'),
(6, 'おむつ交換', 'おむつこうかん', 'omutsu kōkan', 'mengganti popok', 'Kata benda', 'Mengganti popok lansia yang tidak bisa ke toilet.', '使用済みのおむつを新しいものに替えること', 'mengganti popok klien yang kotor dengan yang baru', 'おむつ交換のときは声をかけます。', 'おむつこうかんのときはこえをかけます。', 'Saat mengganti popok, kami menyapa klien terlebih dahulu.', 16, 'kaigo'),
(6, '陰部洗浄', 'いんぶせんじょう', 'inbu senjō', 'membersihkan area kemaluan', 'Kata benda', 'Membersihkan area kemaluan lansia agar tetap higienis.', '陰部を清潔に洗い流すこと', 'membersihkan area genital klien untuk menjaga kebersihan dan mencegah infeksi', 'おむつ交換の際に陰部洗浄を行います。', 'おむつこうかんのさいにいんぶせんじょうをおこないます。', 'Saat mengganti popok, kami membersihkan area kemaluan.', 17, 'kaigo'),
(6, '清潔保持', 'せいけつほじ', 'seiketsu hoji', 'menjaga kebersihan', 'Kata benda', 'Menjaga kebersihan tubuh dan lingkungan lansia.', '体や環境を清潔に保つこと', 'menjaga kebersihan tubuh maupun lingkungan klien agar tetap sehat', '皮膚の清潔保持は感染予防に大切です。', 'ひふのせいけつほじはかんせんよぼうにたいせつです。', 'Menjaga kebersihan kulit penting untuk mencegah infeksi.', 18, 'kaigo'),
(6, '見守り', 'みまもり', 'mimamori', 'pengawasan', 'Kata benda', 'Mengawasi lansia agar aman tanpa terlalu banyak membantu.', '安全のためにそばで様子を見ること', 'mengawasi klien dari dekat demi keselamatan tanpa memberi bantuan berlebih', '自立を促すために見守りを大切にします。', 'じりつをうながすためにみまもりをたいせつにします。', 'Kami mengutamakan pengawasan untuk mendorong kemandirian.', 19, 'kaigo'),
(6, '声かけ', 'こえかけ', 'koekake', 'menyapa atau memberi aba-aba', 'Kata benda', 'Menyapa lansia sebelum dan selama melakukan bantuan.', '介助の前後に言葉をかけること', 'menyapa atau memberi aba-aba kepada klien sebelum dan saat melakukan tindakan', '介助の前に必ず声かけをします。', 'かいじょのまえにかならずこえかけをします。', 'Sebelum membantu, kami selalu menyapa klien terlebih dahulu.', 20, 'kaigo'),
(6, '全介助', 'ぜんかいじょ', 'zen kaijo', 'bantuan penuh', 'Kata benda', 'Bantuan total karena lansia tidak bisa melakukan sendiri.', 'すべての動作を介助者が行うこと', 'kondisi di mana seluruh aktivitas klien dilakukan sepenuhnya oleh pendamping', 'この方は食事が全介助です。', 'このかたはしょくじがぜんかいじょです。', 'Klien ini memerlukan bantuan penuh untuk makan.', 21, 'kaigo'),
(6, '一部介助', 'いちぶかいじょ', 'ichibu kaijo', 'bantuan sebagian', 'Kata benda', 'Bantuan sebagian saat lansia masih bisa melakukan sebagian sendiri.', '動作の一部だけを手伝うこと', 'bantuan hanya pada sebagian aktivitas yang tidak bisa dilakukan klien sendiri', '更衣は一部介助で対応します。', 'こういはいちぶかいじょでたいおうします。', 'Untuk ganti baju, kami memberi bantuan sebagian saja.', 22, 'kaigo'),
(6, '自立支援', 'じりつしえん', 'jiritsu shien', 'dukungan kemandirian', 'Kata benda', 'Mendukung lansia agar bisa melakukan aktivitas sendiri.', '本人ができることを増やす支援', 'dukungan agar klien dapat melakukan sebanyak mungkin aktivitas secara mandiri', '自立支援を意識して介護します。', 'じりつしえんをいしきしてかいごします。', 'Kami merawat dengan kesadaran untuk mendukung kemandirian.', 23, 'kaigo'),
(6, '残存機能', 'ざんぞんきのう', 'zanzon kinō', 'fungsi yang tersisa', 'Kata benda', 'Kemampuan tubuh lansia yang masih berfungsi dan dimanfaatkan.', 'まだ残っている体の働き', 'kemampuan tubuh klien yang masih ada dan dimanfaatkan dalam perawatan', '残存機能を生かした介助をします。', 'ざんぞんきのうをいかしたかいじょをします。', 'Kami memberi bantuan dengan memanfaatkan fungsi yang masih tersisa.', 24, 'kaigo'),
(6, '介助量', 'かいじょりょう', 'kaijoryō', 'tingkat bantuan', 'Kata benda', 'Banyaknya bantuan yang dibutuhkan oleh lansia.', '必要な介助の度合い', 'seberapa banyak bantuan yang dibutuhkan klien dalam suatu aktivitas', '体調により介助量が変わります。', 'たいちょうによりかいじょりょうがかわります。', 'Tingkat bantuan berubah sesuai kondisi tubuh klien.', 25, 'kaigo'),
(6, '足浴', 'そくよく', 'sokuyoku', 'merendam kaki', 'Kata benda', 'Membersihkan dan menghangatkan kaki lansia dengan air hangat.', '足だけをお湯で洗うこと', 'membersihkan dan menghangatkan kaki klien dengan air hangat', '寝る前の足浴でよく眠れます。', 'ねるまえのそくよくでよくねむれます。', 'Merendam kaki sebelum tidur membuat tidur lebih nyenyak.', 26, 'kaigo'),
(6, '手浴', 'しゅよく', 'shuyoku', 'merendam tangan', 'Kata benda', 'Membersihkan dan menghangatkan tangan lansia dengan air hangat.', '手だけをお湯で洗うこと', 'membersihkan dan menghangatkan tangan klien dengan air hangat', '手浴をすると指が動かしやすくなります。', 'しゅよくをするとゆびがうごかしやすくなります。', 'Setelah merendam tangan, jari menjadi lebih mudah digerakkan.', 27, 'kaigo'),
(6, '洗髪', 'せんぱつ', 'senpatsu', 'mencuci rambut', 'Kata benda', 'Mencuci rambut dan kulit kepala lansia.', '髪を洗うこと', 'membersihkan rambut dan kulit kepala klien', 'ベッドの上で洗髪をします。', 'ベッドのうえでせんぱつをします。', 'Kami mencuci rambut di atas tempat tidur.', 28, 'kaigo'),
(6, '爪切り', 'つめきり', 'tsumekiri', 'memotong kuku', 'Kata benda', 'Memotong kuku tangan dan kaki lansia.', '爪を切って整えること', 'memotong dan merapikan kuku tangan dan kaki klien', '入浴後は爪が柔らかく爪切りが楽です。', 'にゅうよくごはつめがやわらかくつめきりがらくです。', 'Setelah mandi, kuku menjadi lunak sehingga lebih mudah dipotong.', 29, 'kaigo'),
(6, '整髪', 'せいはつ', 'seihatsu', 'merapikan rambut', 'Kata benda', 'Menyisir dan merapikan rambut lansia.', '髪をとかして整えること', 'menyisir dan merapikan rambut klien agar terlihat rapi', '鏡を見ながら整髪を手伝います。', 'かがみをみながらせいはつをてつだいます。', 'Kami membantu merapikan rambut sambil bercermin.', 30, 'kaigo'),
(6, '髭剃り', 'ひげそり', 'higesori', 'mencukur jenggot', 'Kata benda', 'Mencukur jenggot dan kumis lansia laki-laki.', 'ひげを剃ること', 'mencukur jenggot dan kumis klien laki-laki agar tampak rapi', '毎朝の髭剃りで身だしなみを整えます。', 'まいあさのひげそりでみだしなみをととのえます。', 'Mencukur jenggot setiap pagi membuat penampilan rapi.', 31, 'kaigo'),
(6, '食事形態', 'しょくじけいたい', 'shokuji keitai', 'bentuk makanan', 'Kata benda', 'Bentuk olahan makanan yang disesuaikan dengan kemampuan menelan.', '飲み込みやすさに合わせた食事の形', 'bentuk penyajian makanan yang disesuaikan dengan kemampuan mengunyah dan menelan klien', '飲み込みに合わせて食事形態を変えます。', 'のみこみにあわせてしょくじけいたいをかえます。', 'Kami menyesuaikan bentuk makanan dengan kemampuan menelan.', 32, 'kaigo'),
(6, '刻み食', 'きざみしょく', 'kizamishoku', 'makanan cincang', 'Kata benda', 'Makanan yang dipotong halus agar mudah dikunyah.', '細かく刻んだ食事', 'makanan yang dipotong halus agar mudah dikunyah oleh klien', '噛む力が弱い方には刻み食を出します。', 'かむちからがよわいかたにはきざみしょくをだします。', 'Untuk klien yang lemah mengunyah, kami sajikan makanan cincang.', 33, 'kaigo'),
(6, '一口大', 'ひとくちだい', 'hitokuchi dai', 'ukuran sekali suap', 'Kata benda', 'Makanan dipotong seukuran satu suapan agar mudah dimakan.', '一口で食べられる大きさ', 'ukuran potongan makanan sebesar satu suapan agar mudah dimakan klien', '食材を一口大に切ります。', 'しょくざいをひとくちだいにきります。', 'Kami memotong bahan makanan seukuran satu suapan.', 34, 'kaigo'),
(6, 'とろみ', 'とろみ', 'toromi', 'pengental cairan', 'Kata benda', 'Menambah kekentalan pada cairan agar tidak tersedak.', '飲み物に粘りをつけること', 'menambahkan kekentalan pada minuman agar klien tidak mudah tersedak', 'お茶にとろみをつけて出します。', 'おちゃにとろみをつけてだします。', 'Kami menyajikan teh yang sudah dikentalkan.', 35, 'kaigo'),
(6, '水分補給', 'すいぶんほきゅう', 'suibun hokyū', 'asupan cairan', 'Kata benda', 'Memberi minum agar lansia tidak dehidrasi.', '体に必要な水分を取ること', 'pemberian cairan agar klien tidak mengalami dehidrasi', 'こまめな水分補給を心がけます。', 'こまめなすいぶんほきゅうをこころがけます。', 'Kami memperhatikan asupan cairan secara rutin.', 36, 'kaigo'),
(6, '配膳', 'はいぜん', 'haizen', 'menyajikan makanan', 'Kata benda', 'Menyiapkan dan mengantar makanan ke meja lansia.', '食事を席に運んで並べること', 'menyiapkan dan menghidangkan makanan ke tempat klien sebelum makan', '食事の時間に配膳をします。', 'しょくじのじかんにはいぜんをします。', 'Kami menyajikan makanan pada jam makan.', 37, 'kaigo'),
(6, '下膳', 'げぜん', 'gezen', 'membereskan piring', 'Kata benda', 'Membereskan dan mengangkat peralatan makan setelah makan.', '食後に食器を片づけること', 'membereskan dan mengangkat peralatan makan setelah klien selesai makan', '食事が終わったら下膳します。', 'しょくじがおわったらげぜんします。', 'Setelah makan selesai, kami membereskan piring.', 38, 'kaigo'),
(6, '抱え上げ', 'かかえあげ', 'kakaeage', 'mengangkat dengan memeluk', 'Kata benda', 'Mengangkat tubuh lansia dengan memeluknya saat berpindah.', '体を抱きかかえて持ち上げること', 'mengangkat tubuh klien dengan memeluk saat memindahkannya', '無理な抱え上げは腰を痛めます。', 'むりなかかえあげはこしをいためます。', 'Mengangkat dengan paksa dapat melukai pinggang.', 39, 'kaigo'),
(6, '介助バー', 'かいじょバー', 'kaijo bā', 'pegangan bantu', 'Kata benda', 'Pegangan yang dipasang untuk membantu lansia berpindah.', '移乗を助ける手すり', 'pegangan atau palang yang membantu klien saat berpindah posisi', '介助バーをつかんで立ち上がります。', 'かいじょバーをつかんでたちあがります。', 'Klien berdiri dengan berpegangan pada pegangan bantu.', 40, 'kaigo'),
(6, '良肢位', 'りょうしい', 'ryōshii', 'posisi anggota tubuh ideal', 'Kata benda', 'Posisi anggota tubuh yang paling nyaman dan aman saat berbaring.', '関節に負担の少ない良い姿勢', 'posisi anggota tubuh yang nyaman dan tidak membebani sendi saat berbaring', 'クッションで良肢位を保ちます。', 'クッションでりょうしいをたもちます。', 'Kami menjaga posisi tubuh ideal menggunakan bantal.', 41, 'kaigo'),
(6, '安楽', 'あんらく', 'anraku', 'kenyamanan', 'Kata benda', 'Kondisi tubuh dan hati lansia yang tenang dan nyaman.', '体も心も楽な状態', 'keadaan tubuh dan hati klien yang tenang serta nyaman', '安楽な姿勢を整えます。', 'あんらくなしせいをととのえます。', 'Kami mengatur posisi yang nyaman bagi klien.', 42, 'kaigo'),
(6, '離床', 'りしょう', 'rishō', 'turun dari tempat tidur', 'Kata benda', 'Membantu lansia bangun dan turun dari tempat tidur.', 'ベッドから起きて離れること', 'membantu klien bangkit dan turun dari tempat tidur untuk beraktivitas', '日中はできるだけ離床を促します。', 'にっちゅうはできるだけりしょうをうながします。', 'Pada siang hari kami mendorong klien turun dari tempat tidur sebisa mungkin.', 43, 'kaigo'),
(6, '臥床', 'がしょう', 'gashō', 'berbaring di tempat tidur', 'Kata benda', 'Kondisi lansia berbaring di tempat tidur.', 'ベッドに横になっている状態', 'keadaan klien berbaring di tempat tidur untuk beristirahat', '体調が悪い日は臥床して休みます。', 'たいちょうがわるいひはがしょうしてやすみます。', 'Pada hari kondisi buruk, klien berbaring dan beristirahat.', 44, 'kaigo'),
(6, 'ギャッジアップ', 'ギャッジアップ', 'gyajji appu', 'menaikkan sandaran ranjang', 'Kata benda', 'Menaikkan bagian kepala tempat tidur agar lansia setengah duduk.', 'ベッドの頭側を上げること', 'menaikkan bagian kepala tempat tidur agar klien berada dalam posisi setengah duduk', '食事の前にギャッジアップをします。', 'しょくじのまえにギャッジアップをします。', 'Sebelum makan, kami menaikkan sandaran tempat tidur.', 45, 'kaigo'),
(6, '排泄誘導', 'はいせつゆうどう', 'haisetsu yūdō', 'mengarahkan ke toilet', 'Kata benda', 'Mengajak dan mengarahkan lansia ke toilet pada waktu tepat.', 'トイレへ行くよう促し案内すること', 'mengajak dan membimbing klien ke toilet pada waktu yang sesuai', '時間を決めて排泄誘導をします。', 'じかんをきめてはいせつゆうどうをします。', 'Kami mengarahkan ke toilet pada waktu yang sudah ditentukan.', 46, 'kaigo'),
(6, '排泄パターン', 'はいせつパターン', 'haisetsu patān', 'pola buang air', 'Kata benda', 'Kebiasaan waktu buang air lansia yang diamati untuk perawatan.', '排尿排便の時間や回数の傾向', 'kebiasaan waktu dan frekuensi buang air klien yang diamati untuk perawatan', '排泄パターンを記録して把握します。', 'はいせつパターンをきろくしてはあくします。', 'Kami mencatat pola buang air untuk memahaminya.', 47, 'kaigo'),
(6, '褥瘡予防', 'じょくそうよぼう', 'jokusō yobō', 'pencegahan luka tekan', 'Kata benda', 'Mencegah timbulnya luka tekan pada lansia yang lama berbaring.', '床ずれを防ぐこと', 'tindakan mencegah munculnya luka dekubitus pada klien yang lama berbaring', '体位変換は褥瘡予防に役立ちます。', 'たいいへんかんはじょくそうよぼうにやくだちます。', 'Perubahan posisi tubuh berguna untuk mencegah luka tekan.', 48, 'kaigo'),
(6, '車椅子移乗', 'くるまいすいじょう', 'kurumaisu ijō', 'pindah ke kursi roda', 'Kata benda', 'Membantu lansia berpindah dari tempat tidur ke kursi roda.', 'ベッドから車椅子へ移ること', 'bantuan saat klien berpindah dari tempat tidur ke kursi roda', '車椅子移乗のときはブレーキを確認します。', 'くるまいすいじょうのときはブレーキをかくにんします。', 'Saat berpindah ke kursi roda, kami memeriksa rem terlebih dahulu.', 49, 'kaigo'),
(6, '半身浴', 'はんしんよく', 'hanshinyoku', 'mandi setengah badan', 'Kata benda', 'Berendam hanya sampai bagian pinggang agar tidak membebani jantung.', '腰までお湯につかる入浴', 'berendam hanya sampai pinggang agar tidak membebani jantung klien', '心臓に負担の少ない半身浴を勧めます。', 'しんぞうにふたんのすくないはんしんよくをすすめます。', 'Kami menganjurkan mandi setengah badan yang ringan bagi jantung.', 50, 'kaigo') ON CONFLICT (level_id, word) DO NOTHING;
